const inJson = $json;
let { from_iso, to_iso } = inJson;

if (!to_iso) {
  const now = new Date();
  to_iso = now.toISOString();
}
if (!from_iso) {
  const to = new Date(to_iso);
  const from = new Date(to.getTime() - 3 * 24 * 60 * 60 * 1000);
  from_iso = from.toISOString();
}

return [{ json: { from_iso, to_iso } }];

