={
  "model": "gpt-4.1-mini",
  "messages": [
    {
      "role": "system",
      "content": "You are a news search agent. Find real news articles about oil or fuel spills in the Black Sea and adjacent straits (Kerch Strait, Bosporus, etc.). Return ONLY incidents that occurred on the sea surface (not prices, not political news). Respond in JSON."
    },
    {
      "role": "user",
      "content": "Find up to 20 unique news articles about oil/fuel spills in the Black Sea region between {{ $json.from_iso }} and {{ $json.to_iso }}. For each article return: src_title, src_url, src_published_at (ISO), short_summary (2-3 sentences)."
    }
  ],
  "temperature": 0.2
}

parameters.jsCode:
const raw = $json.choices[0].message.content || '';
// Вирізати JSON-масив з відповіді
const match = raw.match(/\[[\s\S]*\]/);
if (!match) {
  return [];
}
let arr;
try {
  arr = JSON.parse(match[0]);
} catch (e) {
  return [];
}

const from_iso = $items('CODE.WINDOW_DEFAULT')[0].json.from_iso;
const to_iso   = $items('CODE.WINDOW_DEFAULT')[0].json.to_iso;

const from = new Date(from_iso);
const to   = new Date(to_iso);

const out = [];
for (const item of arr) {
  const p = new Date(item.src_published_at);
  if (isNaN(p.getTime())) continue;
  if (p < from || p > to) continue;

  out.push({
    json: {
      src_title: item.src_title,
      src_url: item.src_url,
      src_published_at: p.toISOString(),
      short_text: item.short_summary,
      window_from: from_iso,
      window_to: to_iso
    }
  });
}

return out;

