const cls = $input.all();                    
const src = $items('CODE.PARSE_GPT_SEARCH');

const out = [];
for (let i = 0; i < src.length; i++) {
  out.push({ json: { ...src[i].json, cls: cls[i].json } });
}
return out;

const rows = $input.all().map(i => i.json);

let summary = '';
if (rows.length === 0) {
  summary = 'Нових подій за цей період не знайдено.';
} else {
  summary = `Знайдено ${rows.length} нових подій, додано до бази.\n\n` +
    rows.map(ev => {
      const date =
        ev.event_date ||
        (ev.src_published_at ? ev.src_published_at.slice(0, 10) : 'дата невідома');

      // Беремо український summary з поля short_summary,
      // якщо його раптом немає — можна спробувати витягнути з llm_extract.short_summary
      const short =
        ev.short_summary ||
        (ev.llm_extract && ev.llm_extract.short_summary) ||
        '';

      return `• [${date}] ${ev.src_title}\n  ${short}\n  Джерело: ${ev.src_url}`;
    }).join('\n\n');
}

return [{
  json: {
    new_events: rows,
    summary_text: summary
  }
}];

// Статические значения
const from_iso = "2010-11-20T13:42:30.620Z";
const to_iso   = "2014-11-23T13:42:30.620Z";

// В n8n нужно вернуть массив items
return [
  {
    json: {
      from_iso,
      to_iso,
    },
  },
];

const items = $input.all();

return items.map(item => {
  const j = item.json;
  let text = '';

  if (Array.isArray(j.output) &&
      j.output[0] &&
      Array.isArray(j.output[0].content) &&
      j.output[0].content[0] &&
      typeof j.output[0].content[0].text === 'string') {
    text = j.output[0].content[0].text;
  } else if (typeof j.text === 'string') {
    text = j.text;
  } else {
    text = '';
  }

  let parsed = {};
  try {
    parsed = JSON.parse(text);
  } catch (e) {
    parsed = {};
  }

  return { json: parsed };
});

// Всі відповіді від OpenAI (embeddings)
const embItems = $input.all();

// Вихідні рядки з ноди PG.GET_NEEDS_EMB (там є id)
const srcItems = $items('PG.GET_NEEDS_EMB', 0);  // 0 – основний вихід

return embItems.map((item, index) => {
  const src = srcItems[index].json;              // беремо відповідний рядок з БД
  const emb = item.json.data[0].embedding;       // вектор з відповіді OpenAI

  return {
    json: {
      id: src.id,                                // ТУТ уже є id
      emb_str: '[' + emb.join(',') + ']'
    }
  };
});

